// export default Taskcard


import React, { useState } from 'react';

const Taskcard = ({ task }) => {
    const [subtask, setSubtask] = useState('');
    const [subtasks, setSubtasks] = useState([]);

    const addtask = () => {
        if (subtask.trim() === '') return;

        const newtask = {
            activity: subtask,
            id: Date.now(),
        };

        setSubtasks(prev => [...prev, newtask]);
        setSubtask(''); // Clear input after adding
    };

    const deletetask = (id) => {
        setSubtasks(prev => prev.filter(sub => sub.id !== id));
    };

    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>
                        {task.title}
                    </div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' onClick={addtask}>
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button'>
                                <img className='icon-img' src='/assets/delete.png' alt="Delete" />
                            </button>
                        </div>
                    </div>
                </div>

                {/* Input for new subtask */}
                <div className='subtask-input-row'>
                    <input
                        className='subtask-input'
                        type='text'
                        placeholder='Enter subtask'
                        value={subtask}
                        onChange={(e) => setSubtask(e.target.value)}
                    />
                </div>

                {/* Subtask list */}
                <div className='sub-tasks'>
                    <ul>
                        {subtasks.map(sub => (
                            <li key={sub.id} className='sub-task-items'>
                                <input type='checkbox' className='subtask-checkbox' />
                                <span className='subtask-label'>{sub.activity}</span>
                                <button className='delete-subtask-btn' onClick={() => deletetask(sub.id)}>✖</button>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
            <Stylesheet />
        </>
    );
};
const Stylesheet = () => {
    return <style>{`
        .task-card {
            margin-bottom: 2rem;
            padding: 10px;
            background-color: var(--secondary-color, #f2f2f2);
            box-sizing: border-box;
            border-radius: 5px;
            width: 280px;
        }
        .taskcard-header {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 5px 10px;
        }
        .task-icons {
            display: flex;
            align-items: center;
            gap: 8px;
        }
        .icon-button {
            background: none;
            border: none;
            cursor: pointer;
        }
        .icon-img {
            height: 20px;
            width: 30px;
        }
        .task-title {
            width: 100px;
            word-wrap: break-word;
            overflow-wrap: break-word;
            white-space: normal;
            font-weight: bold;
        }
        .subtask-input-row {
            margin: 10px 0;
        }
        .subtask-input {
            width: 100%;
            padding: 8px;
            border: 1px solid #ccc;
            border-radius: 4px;
        }
        .sub-tasks ul {
            padding-left: 20px;
            margin: 0;
        }
        .sub-task-items {
            display: flex;
            align-items: center;
            margin-bottom: 6px;
        }
        .subtask-checkbox {
            margin-right: 8px;
        }
        .subtask-label {
            flex-grow: 1;
        }
        .delete-subtask-btn {
            background: none;
            border: none;
            color: red;
            font-size: 16px;
            margin-left: 8px;
            cursor: pointer;
        }
    `}</style>
}
export default Taskcard
